script:
export const meta={name:'pass7-confirm',description:'Pass-7: 2-agent confirmation of 6 fixes',phases:[{title:'Confirm'}]}
const ROOT='/Users/[REDACTED]/hc-assay'
const FIXES=[{"id": "J-001", "file": "scripts/capture_transcripts.py", "what": "scrubber FAILS CLOSED: decode errors='replace' (always scrub text), classify binary by a NUL byte not UTF-8 validity \u2014 fixes the CV-O-1 strict-decode fail-open re-leak.", "test": "test_scrub_fails_closed_on_invalid_utf8_bytes, test_copy_scrubbed_scrubs_file_with_invalid_utf8"}, {"id": "J-002", "file": "scripts/capture_transcripts.py", "what": "operator full display name redacted (from git user.name / ASSAY_SCRUB_NAMES), whitespace-flexible + length-guarded, applied in _scrub.", "test": "test_scrub_redacts_operator_display_name"}, {"id": "J-003", "file": ".github/workflows/ci.yml + requirements-build.lock", "what": "hashed build backend (requirements-build.lock, hatchling==1.30.1) installed + --no-build-isolation editable install + sync-check; no live un-hashed hatchling fetch.", "test": "test_ci_pins_build_backend_and_disables_live_build_isolation"}, {"id": "J-004", "file": "src/assay_engine/observability/tracking.py", "what": "_experiment_id re-fetches the experiment on a concurrent create race (RESOURCE_ALREADY_EXISTS) instead of propagating and dropping the run.", "test": "test_experiment_id_survives_concurrent_create_race"}, {"id": "J-005", "file": "tests/integration/test_reasoning_drain.py", "what": "T3 transient tests now assert the exact transient class (not the base ReasoningError that RateLimit/Permanent subclass) so a mis-classification is caught.", "test": "test_t3_empty_reply_raises_transient, test_t3_generic_error_maps_to_transient, test_t3_sdk_raises_mid_stream_maps_to_transient (_assert_transient)"}, {"id": "J-006", "file": ".github/workflows/ci.yml", "what": "license gate scans the dependency set, not entire site-packages (dropped --with-system).", "test": "test_ci_license_gate_scopes_to_dependency_set"}]
const V={type:'object',required:['fix_id','appropriate','complete','verdict','reasoning'],properties:{fix_id:{type:'string'},appropriate:{type:'boolean'},complete:{type:'boolean'},verdict:{type:'string',enum:['CONFIRMED','CONCERN']},reasoning:{type:'string'}}}
const pr=(f,n)=>`You are confirmer #${n}, independent. Confirm this fix is BOTH appropriate (correct, no regression, idiomatic) AND complete (the named test DISCRIMINATES — fails if reverted). Read the actual changed file + test at ${ROOT}.\nFix ${f.id} in ${f.file}\nWhat: ${f.what}\nTest(s): ${f.test}\nVerdict CONFIRMED or CONCERN; be specific.`
phase('Confirm')
const r=await pipeline(FIXES,f=>parallel([()=>agent(pr(f,1),{label:'cA:'+f.id,phase:'Confirm',schema:V}),()=>agent(pr(f,2),{label:'cB:'+f.id,phase:'Confirm',schema:V})]),
  (vs,f)=>{const[a,b]=vs.filter(Boolean);return{fix_id:f.id,both_confirmed:a&&b&&a.verdict==='CONFIRMED'&&b.verdict==='CONFIRMED',a:a?{v:a.verdict,why:a.reasoning}:null,b:b?{v:b.verdict,why:b.reasoning}:null}})
const concerns=r.filter(x=>!x.both_confirmed)
log('CONFIRMED '+r.filter(x=>x.both_confirmed).length+'/'+r.length+'; CONCERNS: '+concerns.map(c=>c.fix_id).join(', '))
return {confirmed_count:r.filter(x=>x.both_confirmed).length,total:r.length,concerns,all:r}
